text:
{
  "formal_minutes": {
    "meeting_title": "UI 테마 패키지 릴리스 준비 상태",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표로 한다."
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표일 뿐이며 최종 공개 릴리스 결정은 아님"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 제안은 있었지만 담당자 배정은 없었다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 시 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "선행 결과 대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "담당자 미지정",
      "source_certainty": "suggested_not_assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 결과 통과 여부를 먼저 확인한다.",
      "스모크 결과가 게시되면 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 action_items.md 트리아지 노트 작성 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 별도로 확정한다.",
      "README 설치 절차 검토는 필요하지만 현재 담당자와 확정 기한이 없음을 유지한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "명시되지 않은 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자가 지정되지 않은 항목에 임의로 owner를 넣지 않는다.",
    "정확한 기한이 없는 항목에 임의의 deadline을 넣지 않는다.",
    "수요일 릴리스는 확정 결정이 아니라 내부 스트레치 목표로만 기록한다.",
    "거절된 제안을 확정 결정처럼 쓰지 않는다.",
    "공개 릴리스는 스모크 테스트 통과 조건부라는 점을 유지한다."
  ]
}
